namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming. She received her PhD from MIT and specializes in CS education research.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques. Prerequisites: CS 101.", Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is an algorithms researcher with publications in top venues. He joined the department in 2018 after industry experience at Google.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "350", Title = "Database Systems", Description = "Relational database design, SQL, indexing, query optimization, and transaction processing.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed database systems and has contributed to several open-source database projects.", IsFeatured = false },
        new() { Id = 4, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "410", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, and practical applications of ML in real-world systems.", Credits = 3, Schedule = "TTh 2:00–3:15 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming. She received her PhD from MIT and specializes in CS education research.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has authored two widely-used calculus textbooks.", IsFeatured = true },
        new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "TTh 9:00–10:15 AM", InstructorName = "Dr. Emily Zhang", InstructorBio = "Dr. Zhang researches applied linear algebra and numerical methods. She holds a joint appointment with the CS department.", IsFeatured = false },
        new() { Id = 7, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "301", Title = "Probability and Statistics", Description = "Probability theory, random variables, statistical inference, and hypothesis testing.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has authored two widely-used calculus textbooks.", IsFeatured = false },
        new() { Id = 8, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with laboratory component.", Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab: F 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist whose research focuses on quantum optics. He has mentored over 50 undergraduate researchers.", IsFeatured = false },
        new() { Id = 9, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Prerequisites: PHYS 101, MATH 101.", Credits = 4, Schedule = "TTh 1:00–2:15 PM, Lab: W 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist whose research focuses on quantum optics. He has mentored over 50 undergraduate researchers.", IsFeatured = false },
        new() { Id = 10, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "110", Title = "College Writing", Description = "Developing effective academic writing skills. Emphasis on argument, evidence, and revision.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Prof. Diana Wells", InstructorBio = "Prof. Wells has taught composition for 20 years and directs the university writing center.", IsFeatured = false },
        new() { Id = 11, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "TTh 11:00 AM–12:15 PM", InstructorName = "Dr. Marcus Johnson", InstructorBio = "Dr. Johnson is a scholar of African American literature and has published three books on the Harlem Renaissance.", IsFeatured = true },
        new() { Id = 12, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the late medieval period.", Credits = 3, Schedule = "MWF 10:00–10:50 AM", InstructorName = "Dr. Patricia Moore", InstructorBio = "Dr. Moore is a medieval historian specializing in cross-cultural exchange along the Silk Road.", IsFeatured = false },
        new() { Id = 13, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "205", Title = "Modern European History", Description = "Europe from the French Revolution to the present. Political, social, and cultural transformations.", Credits = 3, Schedule = "TTh 3:30–4:45 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant specializes in 20th-century European history with a focus on Cold War diplomacy.", IsFeatured = false },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();
}

